import { useState, useEffect, useRef } from "react";

// ── Balloon colours ──────────────────────────────────────────────
const BALLOON_COLORS = [
  ["#FF6B9D", "#FF3D7F"],
  ["#FFD93D", "#FFC300"],
  ["#6BCB77", "#4CAF50"],
  ["#4D96FF", "#1565C0"],
  ["#FF922B", "#E64D00"],
  ["#CC5DE8", "#9C27B0"],
  ["#FF6B6B", "#E53935"],
  ["#38D9A9", "#00897B"],
];

function seeded(seed) {
  let s = seed;
  return () => { s = (s * 16807 + 0) % 2147483647; return (s - 1) / 2147483646; };
}

function generateBalloons(count = 18) {
  const rand = seeded(42);
  return Array.from({ length: count }, (_, i) => ({
    id: i,
    x: rand() * 100,
    color: BALLOON_COLORS[i % BALLOON_COLORS.length],
    size: 38 + rand() * 28,
    duration: 7 + rand() * 8,
    delay: rand() * 6,
    sway: 20 + rand() * 30,
  }));
}

const BALLOONS = generateBalloons(18);

// ── Confetti ──────────────────────────────────────────────────────
const CONFETTI_COLORS = ["#FF6B9D","#FFD93D","#6BCB77","#4D96FF","#CC5DE8","#FF922B","#FF6B6B","#ffffff"];
function generateConfetti(count = 60) {
  const rand = seeded(99);
  return Array.from({ length: count }, (_, i) => ({
    id: i,
    x: rand() * 100,
    color: CONFETTI_COLORS[i % CONFETTI_COLORS.length],
    size: 6 + rand() * 8,
    duration: 4 + rand() * 5,
    delay: rand() * 4,
    rotate: rand() * 360,
    shape: rand() > 0.5 ? "square" : "circle",
  }));
}
const CONFETTI = generateConfetti(60);

// ── Candle flicker ────────────────────────────────────────────────
function Candle({ color, x, height = 28 }) {
  return (
    <g transform={`translate(${x}, 0)`}>
      {/* candle body */}
      <rect x={-4} y={-height} width={8} height={height} rx={3} fill={color} />
      {/* wick */}
      <line x1={0} y1={-height} x2={0} y2={-height - 6} stroke="#555" strokeWidth={1.5} />
      {/* flame outer */}
      <ellipse cx={0} cy={-height - 12} rx={5} ry={8} fill="#FFD93D" opacity={0.9}>
        <animate attributeName="ry" values="8;10;7;9;8" dur="0.6s" repeatCount="indefinite" />
        <animate attributeName="rx" values="5;4;6;5;5" dur="0.5s" repeatCount="indefinite" />
        <animate attributeName="cy" values={`${-height-12};${-height-14};${-height-11};${-height-13};${-height-12}`} dur="0.55s" repeatCount="indefinite" />
      </ellipse>
      {/* flame inner */}
      <ellipse cx={0} cy={-height - 10} rx={2.5} ry={5} fill="#FF922B" opacity={0.85}>
        <animate attributeName="ry" values="5;6;4;5;5" dur="0.5s" repeatCount="indefinite" />
      </ellipse>
      {/* glow */}
      <ellipse cx={0} cy={-height - 12} rx={10} ry={10} fill="#FFD93D" opacity={0.15}>
        <animate attributeName="opacity" values="0.15;0.25;0.1;0.2;0.15" dur="0.6s" repeatCount="indefinite" />
      </ellipse>
    </g>
  );
}

const CANDLE_DEFS = [
  { color: "#FF6B9D", x: -52, h: 26 },
  { color: "#FFD93D", x: -36, h: 32 },
  { color: "#6BCB77", x: -20, h: 24 },
  { color: "#4D96FF", x: 0,   h: 30 },
  { color: "#CC5DE8", x: 20,  h: 26 },
  { color: "#FF922B", x: 36,  h: 32 },
  { color: "#FF6B6B", x: 52,  h: 28 },
];

function BirthdayCake() {
  return (
    <svg width="220" height="190" viewBox="-110 -100 220 190" style={{ overflow: "visible" }}>
      {/* plate shadow */}
      <ellipse cx={0} cy={88} rx={96} ry={10} fill="#0004" />

      {/* bottom tier */}
      <rect x={-90} y={30} width={180} height={60} rx={12} fill="#FF6B9D" />
      <rect x={-90} y={30} width={180} height={14} rx={6} fill="#FF3D7F" />
      {/* bottom tier frosting drips */}
      {[-70,-50,-30,-10,10,30,50,70].map((dx,i)=>(
        <ellipse key={i} cx={dx} cy={30} rx={8} ry={10} fill="#fff" opacity={0.85} />
      ))}
      {/* bottom tier decoration dots */}
      {[-60,-30,0,30,60].map((dx,i)=>(
        <circle key={i} cx={dx} cy={60} r={5} fill="#FFD93D" />
      ))}

      {/* middle tier */}
      <rect x={-64} y={-10} width={128} height={42} rx={10} fill="#CC5DE8" />
      <rect x={-64} y={-10} width={128} height={12} rx={6} fill="#9C27B0" />
      {[-46,-22,2,26,50].map((dx,i)=>(
        <ellipse key={i} cx={dx} cy={-10} rx={7} ry={9} fill="#fff" opacity={0.85} />
      ))}
      {[-36,0,36].map((dx,i)=>(
        <circle key={i} cx={dx} cy={20} r={5} fill="#FF922B" />
      ))}

      {/* top tier */}
      <rect x={-42} y={-48} width={84} height={40} rx={8} fill="#FFD93D" />
      <rect x={-42} y={-48} width={84} height={10} rx={5} fill="#FFC300" />
      {[-28,-8,12,32].map((dx,i)=>(
        <ellipse key={i} cx={dx} cy={-48} rx={6} ry={8} fill="#fff" opacity={0.85} />
      ))}

      {/* candles */}
      <g transform="translate(0,-48)">
        {CANDLE_DEFS.map((c,i) => (
          <Candle key={i} color={c.color} x={c.x} height={c.h} />
        ))}
      </g>

      {/* "Happy Birthday" text on cake */}
      <text x={0} y={72} textAnchor="middle" fontSize="11" fontFamily="'Pacifico',cursive" fill="#fff" opacity={0.9}>
        Happy Birthday!
      </text>
    </svg>
  );
}

// ── Timer ring ────────────────────────────────────────────────────
function TimerRing({ progress, seconds }) {
  const r = 22;
  const circ = 2 * Math.PI * r;
  const dash = circ * (1 - progress);
  return (
    <div style={{ position: "relative", width: 60, height: 60, flexShrink: 0 }}>
      <svg width={60} height={60} style={{ transform: "rotate(-90deg)" }}>
        <circle cx={30} cy={30} r={r} fill="none" stroke="rgba(255,255,255,0.15)" strokeWidth={4} />
        <circle
          cx={30} cy={30} r={r} fill="none"
          stroke="#FFD93D" strokeWidth={4}
          strokeDasharray={circ}
          strokeDashoffset={dash}
          strokeLinecap="round"
          style={{ transition: "stroke-dashoffset 1s linear" }}
        />
      </svg>
      <span style={{
        position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center",
        fontFamily: "'Space Mono', monospace", fontSize: 15, fontWeight: 700, color: "#FFD93D"
      }}>{seconds}</span>
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────
const LOCK_SECONDS = 13;

export default function BirthdayPage() {
  const [timeLeft, setTimeLeft] = useState(LOCK_SECONDS);
  const [canClose, setCanClose] = useState(false);
  const [modalOpen, setModalOpen] = useState(true);
  const [titleVisible, setTitleVisible] = useState(false);
  const intervalRef = useRef(null);

  useEffect(() => {
    // stagger title entrance
    setTimeout(() => setTitleVisible(true), 300);

    intervalRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1) {
          clearInterval(intervalRef.current);
          setCanClose(true);
          return 0;
        }
        return t - 1;
      });
    }, 1000);
    return () => clearInterval(intervalRef.current);
  }, []);

  const progress = (LOCK_SECONDS - timeLeft) / LOCK_SECONDS;

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg,#1a0533 0%,#2d1b4e 40%,#0d2137 100%)",
      fontFamily: "'Nunito', sans-serif",
      overflow: "hidden",
      position: "relative",
    }}>
      {/* Google fonts */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Pacifico&family=Nunito:wght@400;600;700;900&family=Space+Mono:wght@700&display=swap');

        @keyframes floatUp {
          0%   { transform: translateY(110vh) translateX(0); opacity:0; }
          5%   { opacity:1; }
          95%  { opacity:1; }
          100% { transform: translateY(-12vh) translateX(var(--sway)); opacity:0; }
        }
        @keyframes sway {
          0%,100% { margin-left: 0; }
          50%      { margin-left: var(--sway); }
        }
        @keyframes confettiFall {
          0%   { transform: translateY(-10vh) rotate(0deg); opacity:1; }
          100% { transform: translateY(110vh) rotate(720deg); opacity:0; }
        }
        @keyframes letterPop {
          0%   { transform: scale(0) rotate(-15deg); opacity:0; }
          60%  { transform: scale(1.2) rotate(4deg); }
          100% { transform: scale(1) rotate(0deg); opacity:1; }
        }
        @keyframes shimmer {
          0%,100% { text-shadow: 0 0 20px #FFD93D88, 0 0 60px #FF6B9D44; }
          50%      { text-shadow: 0 0 40px #FFD93Dcc, 0 0 100px #FF6B9D88, 0 0 6px #fff; }
        }
        @keyframes pulse {
          0%,100% { box-shadow: 0 0 0 0 rgba(255,217,61,0.4); }
          50%      { box-shadow: 0 0 0 14px rgba(255,217,61,0); }
        }
        @keyframes modalIn {
          0%   { transform: scale(0.6) translateY(40px); opacity:0; }
          70%  { transform: scale(1.04) translateY(-4px); }
          100% { transform: scale(1) translateY(0); opacity:1; }
        }
        @keyframes sparkle {
          0%,100% { opacity:0; transform:scale(0); }
          50%      { opacity:1; transform:scale(1); }
        }
        .balloon { position:absolute; bottom:-10%; animation: floatUp var(--dur) var(--delay) ease-in infinite; }
        .confetti-piece { position:absolute; top:-5%; animation: confettiFall var(--dur) var(--delay) linear infinite; }
      `}</style>

      {/* ── Balloons ── */}
      {BALLOONS.map(b => (
        <div key={b.id} className="balloon" style={{
          left: `${b.x}%`,
          "--dur": `${b.duration}s`,
          "--delay": `${b.delay}s`,
          "--sway": `${b.sway}px`,
        }}>
          <svg width={b.size} height={b.size * 1.3} viewBox="0 0 60 78" style={{ filter: "drop-shadow(0 4px 12px rgba(0,0,0,0.3))" }}>
            <defs>
              <radialGradient id={`bg${b.id}`} cx="35%" cy="30%" r="65%">
                <stop offset="0%" stopColor={b.color[0]} stopOpacity="1" />
                <stop offset="100%" stopColor={b.color[1]} stopOpacity="1" />
              </radialGradient>
            </defs>
            {/* balloon body */}
            <ellipse cx={30} cy={28} rx={26} ry={28} fill={`url(#bg${b.id})`} />
            {/* highlight */}
            <ellipse cx={20} cy={16} rx={8} ry={6} fill="rgba(255,255,255,0.35)" />
            {/* knot */}
            <ellipse cx={30} cy={57} rx={4} ry={3} fill={b.color[1]} />
            {/* string */}
            <path d={`M30 60 Q${22+b.id%10} 68 30 78`} stroke={b.color[1]} strokeWidth={1.5} fill="none" opacity={0.7} />
          </svg>
        </div>
      ))}

      {/* ── Confetti ── */}
      {CONFETTI.map(c => (
        <div key={c.id} className="confetti-piece" style={{
          left: `${c.x}%`,
          "--dur": `${c.duration}s`,
          "--delay": `${c.delay}s`,
          width: c.size,
          height: c.size,
          background: c.color,
          borderRadius: c.shape === "circle" ? "50%" : "2px",
          transform: `rotate(${c.rotate}deg)`,
          opacity: 0.85,
        }} />
      ))}

      {/* ── Background page content (blurred when modal open) ── */}
      <div style={{
        filter: modalOpen ? "blur(6px) brightness(0.55)" : "none",
        transition: "filter 0.6s ease",
        padding: "60px 24px",
        textAlign: "center",
        pointerEvents: modalOpen ? "none" : "auto",
      }}>
        {/* Main heading */}
        <div style={{ marginBottom: 8 }}>
          {"HAPPY BIRTHDAY".split("").map((ch, i) => (
            <span key={i} style={{
              display: "inline-block",
              fontFamily: "'Pacifico', cursive",
              fontSize: "clamp(2rem, 6vw, 5rem)",
              color: i % 2 === 0 ? "#FFD93D" : "#FF6B9D",
              animation: titleVisible ? `letterPop 0.5s cubic-bezier(.34,1.56,.64,1) ${i * 0.06}s both` : "none",
              marginRight: ch === " " ? "0.4em" : "0.02em",
            }}>{ch}</span>
          ))}
        </div>
        <div style={{ marginBottom: 40 }}>
          {"SHRUTI".split("").map((ch, i) => (
            <span key={i} style={{
              display: "inline-block",
              fontFamily: "'Pacifico', cursive",
              fontSize: "clamp(3rem, 9vw, 8rem)",
              color: "#fff",
              animation: titleVisible
                ? `letterPop 0.55s cubic-bezier(.34,1.56,.64,1) ${0.84 + i * 0.08}s both, shimmer 3s ${1.5 + i * 0.08}s ease-in-out infinite`
                : "none",
              marginRight: "0.04em",
            }}>{ch}</span>
          ))}
        </div>

        {/* Cake */}
        <div style={{ display: "flex", justifyContent: "center", marginBottom: 48 }}>
          <BirthdayCake />
        </div>

        {/* Subtitle */}
        <p style={{
          fontFamily: "'Nunito', sans-serif",
          fontWeight: 700,
          fontSize: "clamp(1.1rem, 2.5vw, 1.8rem)",
          color: "rgba(255,255,255,0.75)",
          letterSpacing: "0.12em",
          textTransform: "uppercase",
        }}>
          🎊 Wishing you a day as magical as you are 🎊
        </p>
      </div>

      {/* ── Birthday Modal ── */}
      {modalOpen && (
        <div style={{
          position: "fixed", inset: 0, zIndex: 100,
          display: "flex", alignItems: "center", justifyContent: "center",
          padding: 16,
        }}>
          <div style={{
            background: "linear-gradient(145deg,#2d1b4e,#1a0533)",
            border: "2px solid rgba(255,217,61,0.35)",
            borderRadius: 28,
            padding: "40px 36px 36px",
            maxWidth: 480,
            width: "100%",
            textAlign: "center",
            boxShadow: "0 30px 80px rgba(0,0,0,0.7), inset 0 1px 0 rgba(255,255,255,0.08)",
            animation: "modalIn 0.6s cubic-bezier(.34,1.56,.64,1) both",
            position: "relative",
            overflow: "hidden",
          }}>
            {/* sparkle corners */}
            {[
              { top: 16, left: 20 }, { top: 16, right: 20 },
              { bottom: 16, left: 20 }, { bottom: 16, right: 20 },
            ].map((pos, i) => (
              <div key={i} style={{
                position: "absolute", ...pos, fontSize: 22,
                animation: `sparkle ${1 + i * 0.3}s ${i * 0.4}s ease-in-out infinite`,
              }}>✨</div>
            ))}

            {/* Mini cake */}
            <div style={{ marginBottom: 8 }}>
              <svg width={110} height={100} viewBox="-55 -55 110 100" style={{ overflow: "visible" }}>
                <rect x={-44} y={10} width={88} height={40} rx={8} fill="#FF6B9D" />
                <rect x={-44} y={10} width={88} height={10} rx={5} fill="#FF3D7F" />
                {[-28,-8,12,32].map((dx,i) => <ellipse key={i} cx={dx} cy={10} rx={6} ry={8} fill="#fff" opacity={0.85} />)}
                <rect x={-28} y={-16} width={56} height={28} rx={6} fill="#FFD93D" />
                <rect x={-28} y={-16} width={56} height={8} rx={4} fill="#FFC300" />
                {[-14,4,22].map((dx,i) => <ellipse key={i} cx={dx} cy={-16} rx={5} ry={7} fill="#fff" opacity={0.85} />)}
                <g transform="translate(0,-16)">
                  {[{c:"#FF6B9D",x:-22,h:18},{c:"#6BCB77",x:-8,h:22},{c:"#4D96FF",x:8,h:18},{c:"#CC5DE8",x:22,h:20}].map((cd,i) => (
                    <Candle key={i} color={cd.c} x={cd.x} height={cd.h} />
                  ))}
                </g>
              </svg>
            </div>

            <h2 style={{
              fontFamily: "'Pacifico', cursive",
              fontSize: "2.2rem",
              color: "#FFD93D",
              margin: "0 0 6px",
              textShadow: "0 0 30px rgba(255,217,61,0.5)",
            }}>Happy Birthday</h2>
            <h1 style={{
              fontFamily: "'Pacifico', cursive",
              fontSize: "3rem",
              color: "#FF6B9D",
              margin: "0 0 16px",
              textShadow: "0 0 40px rgba(255,107,157,0.6)",
            }}>Shruti! 🎉</h1>

            <p style={{
              color: "rgba(255,255,255,0.75)",
              fontSize: "1rem",
              lineHeight: 1.6,
              marginBottom: 28,
              fontWeight: 600,
            }}>
              Something special is being prepared just for you.<br/>
              Hold on for just a moment… ✨
            </p>

            {/* Timer + message row */}
            <div style={{
              display: "flex",
              alignItems: "center",
              gap: 16,
              background: "rgba(255,255,255,0.05)",
              borderRadius: 16,
              padding: "14px 20px",
              marginBottom: 20,
              border: "1px solid rgba(255,255,255,0.08)",
            }}>
              <TimerRing progress={progress} seconds={timeLeft} />
              <p style={{
                margin: 0, textAlign: "left",
                color: canClose ? "#6BCB77" : "rgba(255,255,255,0.65)",
                fontSize: "0.92rem",
                fontWeight: 600,
                transition: "color 0.4s",
              }}>
                {canClose
                  ? "🎊 Everything's ready! Click below to continue."
                  : `Fetching your birthday surprise… ${timeLeft}s`}
              </p>
            </div>

            {/* CTA button */}
            <button
              onClick={() => canClose && setModalOpen(false)}
              disabled={!canClose}
              style={{
                width: "100%",
                padding: "15px 24px",
                borderRadius: 14,
                border: "none",
                cursor: canClose ? "pointer" : "not-allowed",
                fontFamily: "'Nunito', sans-serif",
                fontWeight: 900,
                fontSize: "1.05rem",
                letterSpacing: "0.05em",
                textTransform: "uppercase",
                background: canClose
                  ? "linear-gradient(135deg,#FF6B9D,#FF3D7F)"
                  : "rgba(255,255,255,0.08)",
                color: canClose ? "#fff" : "rgba(255,255,255,0.3)",
                transition: "all 0.4s ease",
                animation: canClose ? "pulse 1.5s ease-in-out infinite" : "none",
                boxShadow: canClose ? "0 8px 32px rgba(255,61,127,0.4)" : "none",
              }}
            >
              {canClose ? "🎂 Let's Celebrate!" : "Please wait…"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
